UPDATE TRANSACTIONS
SET CARRIER_CODE = #{carrierCode},
    INVOICE_NO   = #{invoiceNo}
WHERE TRANSACTION_ID = #{transactionId}
  AND SELLER_EMAIL   = #{email}

mapper.select:
SELECT CARRIER_CODE AS carrierCode,
       INVOICE_NO   AS invoiceNo
FROM TRANSACTIONS
WHERE TRANSACTION_ID = #{transactionId}
  AND SELLER_EMAIL   = #{email}

mapper.update:
UPDATE PRODUCTS
SET PRODUCT_NAME      = #{productName},
    PRODUCT_PRICE     = #{productPrice, jdbcType=NUMERIC},
    TRADE_STATUS      = #{tradeStatus},
    PRODUCT_DESC      = #{productDesc, jdbcType=VARCHAR},
    CATEGORY_NO       = #{categoryNo, jdbcType=NUMERIC},
    PRODUCT_CONDITION = #{productCondition, jdbcType=VARCHAR},
    TRADE_METHOD      = #{tradeMethod, jdbcType=VARCHAR}
WHERE PRODUCT_NO   = #{productNo}
  AND SELLER_EMAIL = #{email}

UPDATE PRODUCT_IMAGE SET IS_MAIN = 'Y'
WHERE PRD_IMG_NO = (
    SELECT MIN(PRD_IMG_NO) FROM PRODUCT_IMAGE WHERE PRODUCT_NO = #{productNo}
)

mapper.delete:
DELETE FROM PRODUCTS
WHERE PRODUCT_NO   = #{productNo}
  AND SELLER_EMAIL = #{email}

mapper.update:
UPDATE ACCOUNTS
SET BANK_NAME      = #{bankName},
    ACCOUNT_NUM    = #{accountNum},
    ACCOUNT_HOLDER = #{accountHolder}
WHERE ACCOUNT_ID = #{accountId} AND EMAIL = #{email}

UPDATE ACCOUNTS
SET IS_PRIMARY = CASE WHEN ACCOUNT_ID = #{accountId} THEN 'Y' ELSE 'N' END
WHERE EMAIL = #{email}

UPDATE DELIVERY_ADDRESS
SET IS_PRIMARY = CASE WHEN DELIVERY_NO = #{deliveryNo} THEN 'Y' ELSE 'N' END
WHERE MEMBER_EMAIL = #{email}

UPDATE TRANSACTIONS
SET TRADE_STATUS = '거래완료'
WHERE TRANSACTION_ID = #{transactionId}
  AND BUYER_EMAIL = #{email}

UPDATE PRODUCTS
SET TRADE_STATUS = '판매완료',
    RESERVED_ROOM_ID = NULL
WHERE PRODUCT_NO = #{productNo}
  AND EXISTS (
      SELECT 1 FROM TRANSACTIONS
      WHERE TRANSACTION_ID = #{transactionId}
        AND BUYER_EMAIL = #{email}
  )
